#[doc = "Sets the preferred cache configuration for the current context.\nOn devices where the L1 cache and shared memory use the same hardware\nresources, this sets through `config` the preferred cache configuration for\nthe current context. This is only a preference. The driver will use\nthe requested configuration if possible, but it is free to choose a different\nconfiguration if required to execute the function. Any function preference\nset via ::cuFuncSetCacheConfig() or ::cuKernelSetCacheConfig() will be preferred over this context-wide\nsetting. Setting the context-wide cache configuration to\n::CU_FUNC_CACHE_PREFER_NONE will cause subsequent kernel launches to prefer\nto not change the cache configuration unless required to launch the kernel.\nThis setting does nothing on devices where the size of the L1 cache and\nshared memory are fixed.\nLaunching a kernel with a different preference than the most recent\npreference setting may insert a device-side synchronization point.\nThe supported cache configurations are:\n- ::CU_FUNC_CACHE_PREFER_NONE: no preference for shared memory or L1 (default)\n- ::CU_FUNC_CACHE_PREFER_SHARED: prefer larger shared memory and smaller L1 cache\n- ::CU_FUNC_CACHE_PREFER_L1: prefer larger L1 cache and smaller shared memory\n- ::CU_FUNC_CACHE_PREFER_EQUAL: prefer equal sized L1 cache and shared memory\n\n# Arguments\n\n* `config` - - Requested cache configuration\n\n# Returns\n\n::CUDA_SUCCESS,\n::CUDA_ERROR_DEINITIALIZED,\n::CUDA_ERROR_NOT_INITIALIZED,\n::CUDA_ERROR_INVALID_CONTEXT,\n::CUDA_ERROR_INVALID_VALUE\n\\notefnerr # See also\n\n> [`::cuCtxCreate,`]\n::cuCtxDestroy,\n::cuCtxGetApiVersion,\n::cuCtxGetCacheConfig,\n::cuCtxGetDevice,\n::cuCtxGetFlags,\n::cuCtxGetLimit,\n::cuCtxPopCurrent,\n::cuCtxPushCurrent,\n::cuCtxSetLimit,\n::cuCtxSynchronize,\n::cuFuncSetCacheConfig,\n::cudaDeviceSetCacheConfig,\n::cuKernelSetCacheConfig"]
pub unsafe fn cuCtxSetCacheConfig(config: CUfunc_cache) -> Result<(), crate::sys::CUresult> {
    let status = unsafe { crate::sys::cuCtxSetCacheConfig(config) };
    if status == crate::sys::CUresult::CUDA_SUCCESS { Ok(()) } else { Err(status) }
}
#[doc = "Gets the context's API version.\nReturns a version number in `version` corresponding to the capabilities of\nthe context (e.g. 3010 or 3020), which library developers can use to direct\ncallers to a specific API version. If `ctx` is NULL, returns the API version\nused to create the currently bound context.\nNote that new API versions are only introduced when context capabilities are\nchanged that break binary compatibility, so the API version and driver version\nmay be different. For example, it is valid for the API version to be 3020 while\nthe driver version is 4020.\n\n# Arguments\n\n* `ctx` -     - Context to check\n* `version` - - Pointer to version\n\n# Returns\n\n::CUDA_SUCCESS,\n::CUDA_ERROR_DEINITIALIZED,\n::CUDA_ERROR_NOT_INITIALIZED,\n::CUDA_ERROR_INVALID_CONTEXT,\n::CUDA_ERROR_INVALID_VALUE,\n::CUDA_ERROR_UNKNOWN\n\\notefnerr # See also\n\n> [`::cuCtxCreate,`]\n::cuCtxDestroy,\n::cuCtxGetDevice,\n::cuCtxGetFlags,\n::cuCtxGetLimit,\n::cuCtxPopCurrent,\n::cuCtxPushCurrent,\n::cuCtxSetCacheConfig,\n::cuCtxSetLimit,\n::cuCtxSynchronize"]
