#[doc = "Get information on memory allocations\nReturns the base address in `*pbase` and size in `*psize` of the allocation\nthat contains the input pointer `dptr.` Both parameters `pbase` and `psize` are optional. If one of them is NULL, it is ignored.\n\n# Arguments\n\n* `pbase` - - Returned base address\n* `psize` - - Returned size of device memory allocation\n* `dptr` -  - Device pointer to query\n\n# Returns\n\n::CUDA_SUCCESS,\n::CUDA_ERROR_DEINITIALIZED,\n::CUDA_ERROR_NOT_INITIALIZED,\n::CUDA_ERROR_INVALID_CONTEXT,\n::CUDA_ERROR_NOT_FOUND,\n::CUDA_ERROR_INVALID_VALUE\n\\notefnerr # See also\n\n> [`::cuArray3DCreate,`] ::cuArray3DGetDescriptor, ::cuArrayCreate,\n::cuArrayDestroy, ::cuArrayGetDescriptor, ::cuMemAlloc, ::cuMemAllocHost,\n::cuMemAllocPitch, ::cuMemcpy2D, ::cuMemcpy2DAsync, ::cuMemcpy2DUnaligned,\n::cuMemcpy3D, ::cuMemcpy3DAsync, ::cuMemcpyAtoA, ::cuMemcpyAtoD,\n::cuMemcpyAtoH, ::cuMemcpyAtoHAsync, ::cuMemcpyDtoA, ::cuMemcpyDtoD, ::cuMemcpyDtoDAsync,\n::cuMemcpyDtoH, ::cuMemcpyDtoHAsync, ::cuMemcpyHtoA, ::cuMemcpyHtoAAsync,\n::cuMemcpyHtoD, ::cuMemcpyHtoDAsync, ::cuMemFree, ::cuMemFreeHost,\n::cuMemGetInfo, ::cuMemHostAlloc,\n::cuMemHostGetDevicePointer, ::cuMemsetD2D8, ::cuMemsetD2D16,\n::cuMemsetD2D32, ::cuMemsetD8, ::cuMemsetD16, ::cuMemsetD32"]
