#[doc = "Returns a graph's dependency edges\nReturns a list of `hGraph's` dependency edges. Edges are returned via corresponding\nindices in `from,` `to` and `edgeData;` that is, the node in `to`[i] has a\ndependency on the node in `from`[i] with data `edgeData`[i]. `from` and `to` may\nboth be NULL, in which case this function only returns the number of edges in\n`numEdges.` Otherwise, `numEdges` entries will be filled in. If `numEdges` is higher\nthan the actual number of edges, the remaining entries in `from` and `to` will be\nset to NULL, and the number of edges actually returned will be written to `numEdges.`\n`edgeData` may alone be NULL, in which case the edges must all have default (zeroed)\nedge data. Attempting a lossy query via NULL `edgeData` will result in\n::CUDA_ERROR_LOSSY_QUERY. If `edgeData` is non-NULL then `from` and `to` must be\nas well.\n\n# Arguments\n\n* `hGraph` -   - Graph to get the edges from\n* `from` -     - Location to return edge endpoints\n* `to` -       - Location to return edge endpoints\n* `edgeData` - - Optional location to return edge data\n* `numEdges` - - See description\n\n# Returns\n\n::CUDA_SUCCESS,\n::CUDA_ERROR_LOSSY_QUERY,\n::CUDA_ERROR_DEINITIALIZED,\n::CUDA_ERROR_NOT_INITIALIZED,\n::CUDA_ERROR_INVALID_VALUE\n\\note_graph_thread_safety \\notefnerr # See also\n\n> [`::cuGraphGetNodes,`]\n::cuGraphGetRootNodes,\n::cuGraphAddDependencies,\n::cuGraphRemoveDependencies,\n::cuGraphNodeGetDependencies,\n::cuGraphNodeGetDependentNodes"]
pub unsafe fn cuGraphGetEdges_v2(hGraph: CUgraph) -> Result<(CUgraphNode, CUgraphNode, CUgraphEdgeData, usize), crate::sys::CUresult> {
    let mut out_1: std::mem::MaybeUninit<CUgraphNode> = std::mem::MaybeUninit::zeroed();
    let mut out_2: std::mem::MaybeUninit<CUgraphNode> = std::mem::MaybeUninit::zeroed();
    let mut out_3: std::mem::MaybeUninit<CUgraphEdgeData> = std::mem::MaybeUninit::zeroed();
    let mut out_4: std::mem::MaybeUninit<usize> = std::mem::MaybeUninit::zeroed();
    let status = unsafe { crate::sys::cuGraphGetEdges_v2(hGraph, out_1.as_mut_ptr() as *mut _, out_2.as_mut_ptr() as *mut _, out_3.as_mut_ptr() as *mut _, out_4.as_mut_ptr() as *mut _) };
    if status as usize == crate::sys::CUresult::CUDA_SUCCESS as usize {
        unsafe { Ok((out_1.assume_init() as CUgraphNode, out_2.assume_init() as CUgraphNode, out_3.assume_init() as CUgraphEdgeData, out_4.assume_init() as usize)) }
    } else {
        Err(unsafe { std::mem::transmute(status) })
    }
}
#[doc = "Returns a node's dependencies\nReturns a list of `node's` dependencies. `dependencies` may be NULL, in which case this\nfunction will return the number of dependencies in `numDependencies.` Otherwise,\n`numDependencies` entries will be filled in. If `numDependencies` is higher than the actual\nnumber of dependencies, the remaining entries in `dependencies` will be set to NULL, and the\nnumber of nodes actually obtained will be returned in `numDependencies.`\nNote that if an edge has non-zero (non-default) edge data and `edgeData` is NULL,\nthis API will return ::CUDA_ERROR_LOSSY_QUERY. If `edgeData` is non-NULL, then\n`dependencies` must be as well.\n\n# Arguments\n\n* `hNode` -           - Node to query\n* `dependencies` -    - Pointer to return the dependencies\n* `edgeData` -        - Optional array to return edge data for each dependency\n* `numDependencies` - - See description\n\n# Returns\n\n::CUDA_SUCCESS,\n::CUDA_ERROR_LOSSY_QUERY,\n::CUDA_ERROR_DEINITIALIZED,\n::CUDA_ERROR_NOT_INITIALIZED,\n::CUDA_ERROR_INVALID_VALUE\n\\note_graph_thread_safety \\notefnerr # See also\n\n> [`::cuGraphNodeGetDependentNodes,`]\n::cuGraphGetNodes,\n::cuGraphGetRootNodes,\n::cuGraphGetEdges,\n::cuGraphAddDependencies,\n::cuGraphRemoveDependencies"]
