#[doc = "Updates node parameters in the child graph node in the given graphExec.\nUpdates the work represented by `hNode` in `hGraphExec` as though the nodes contained\nin `hNode's` graph had the parameters contained in `childGraph's` nodes at instantiation.\n`hNode` must remain in the graph which was used to instantiate `hGraphExec.`\nChanged edges to and from `hNode` are ignored.\nThe modifications only affect future launches of `hGraphExec.`  Already enqueued\nor running launches of `hGraphExec` are not affected by this call.  `hNode` is also\nnot modified by this call.\nThe topology of `childGraph,` as well as the node insertion order,  must match that\nof the graph contained in `hNode.`  See ::cuGraphExecUpdate() for a list of restrictions\non what can be updated in an instantiated graph.  The update is recursive, so child graph\nnodes contained within the top level child graph will also be updated.\n\n# Arguments\n\n* `hGraphExec` - - The executable graph in which to set the specified node\n* `hNode` -      - Host node from the graph which was used to instantiate graphExec\n* `childGraph` - - The graph supplying the updated parameters\n\n# Returns\n\n::CUDA_SUCCESS,\n::CUDA_ERROR_INVALID_VALUE,\n\\note_graph_thread_safety \\notefnerr # See also\n\n> [`::cuGraphExecNodeSetParams,`]\n::cuGraphAddChildGraphNode,\n::cuGraphChildGraphNodeGetGraph,\n::cuGraphExecKernelNodeSetParams,\n::cuGraphExecMemcpyNodeSetParams,\n::cuGraphExecMemsetNodeSetParams,\n::cuGraphExecHostNodeSetParams,\n::cuGraphExecEventRecordNodeSetEvent,\n::cuGraphExecEventWaitNodeSetEvent,\n::cuGraphExecExternalSemaphoresSignalNodeSetParams,\n::cuGraphExecExternalSemaphoresWaitNodeSetParams,\n::cuGraphExecUpdate,\n::cuGraphInstantiate"]
pub unsafe fn cuGraphExecChildGraphNodeSetParams(hGraphExec: CUgraphExec, hNode: CUgraphNode, childGraph: CUgraph) -> Result<(), crate::sys::CUresult> {
    let status = unsafe { crate::sys::cuGraphExecChildGraphNodeSetParams(hGraphExec, hNode, childGraph) };
    if status == crate::sys::CUresult::CUDA_SUCCESS { Ok(()) } else { Err(status) }
}
#[doc = "Sets the event for an event record node in the given graphExec\nSets the event of an event record node in an executable graph `hGraphExec.`\nThe node is identified by the corresponding node `hNode` in the\nnon-executable graph, from which the executable graph was instantiated.\nThe modifications only affect future launches of `hGraphExec.` Already\nenqueued or running launches of `hGraphExec` are not affected by this call.\n`hNode` is also not modified by this call.\n\n# Arguments\n\n* `hGraphExec` - - The executable graph in which to set the specified node\n* `hNode` -      - event record node from the graph from which graphExec was instantiated\n* `event` -      - Updated event to use\n\n# Returns\n\n::CUDA_SUCCESS,\n::CUDA_ERROR_INVALID_VALUE,\n\\note_graph_thread_safety \\notefnerr # See also\n\n> [`::cuGraphExecNodeSetParams,`]\n::cuGraphAddEventRecordNode,\n::cuGraphEventRecordNodeGetEvent,\n::cuGraphEventWaitNodeSetEvent,\n::cuEventRecordWithFlags,\n::cuStreamWaitEvent,\n::cuGraphExecKernelNodeSetParams,\n::cuGraphExecMemcpyNodeSetParams,\n::cuGraphExecMemsetNodeSetParams,\n::cuGraphExecHostNodeSetParams,\n::cuGraphExecChildGraphNodeSetParams,\n::cuGraphExecEventWaitNodeSetEvent,\n::cuGraphExecExternalSemaphoresSignalNodeSetParams,\n::cuGraphExecExternalSemaphoresWaitNodeSetParams,\n::cuGraphExecUpdate,\n::cuGraphInstantiate"]
