#[doc = "Creates a green context with a specified set of resources.\nThis API creates a green context with the resources specified in the descriptor `desc` and\nreturns it in the handle represented by `phCtx.` This API will retain the primary context on device `dev,`\nwhich will is released when the green context is destroyed. It is advised to have the primary context active\nbefore calling this API to avoid the heavy cost of triggering primary context initialization and\ndeinitialization multiple times.\nThe API does not set the green context current. In order to set it current, you need to explicitly set it current\nby first converting the green context to a CUcontext using ::cuCtxFromGreenCtx and subsequently calling\n::cuCtxSetCurrent / ::cuCtxPushCurrent. It should be noted that a green context can be current to only one\nthread at a time. There is no internal synchronization to make API calls accessing the same green context\nfrom multiple threads work.\nNote: The API is not supported on 32-bit platforms.\n\n# Arguments\n\n* `phCtx` - - Pointer for the output handle to the green context\n* `desc` - - Descriptor generated via ::cuDevResourceGenerateDesc which contains the set of resources to be used\n* `dev` - - Device on which to create the green context.\n* `flags` - - One of the supported green context creation flags. `CU_GREEN_CTX_DEFAULT_STREAM` is required.\nThe supported flags are:\n- `CU_GREEN_CTX_DEFAULT_STREAM` : Creates a default stream to use inside the green context. Required.\n\n# Returns\n\n::CUDA_SUCCESS,\n::CUDA_ERROR_DEINITIALIZED,\n::CUDA_ERROR_NOT_INITIALIZED,\n::CUDA_ERROR_INVALID_DEVICE,\n::CUDA_ERROR_INVALID_VALUE,\n::CUDA_ERROR_NOT_SUPPORTED,\n::CUDA_ERROR_OUT_OF_MEMORY\n\n# See also\n\n> [`::cuGreenCtxDestroy,`]\n::cuCtxFromGreenCtx,\n::cuCtxSetCurrent,\n::cuCtxPushCurrent,\n::cuDevResourceGenerateDesc,\n::cuDevicePrimaryCtxRetain,\n::cuCtxCreate"]
pub unsafe fn cuGreenCtxCreate(desc: CUdevResourceDesc, dev: CUdevice, flags: u32) -> Result<CUgreenCtx, crate::sys::CUresult> {
    let mut out_0: std::mem::MaybeUninit<CUgreenCtx> = std::mem::MaybeUninit::zeroed();
    let status = unsafe { crate::sys::cuGreenCtxCreate(out_0.as_mut_ptr() as *mut _, desc, dev, flags as _) };
    if status as usize == crate::sys::CUresult::CUDA_SUCCESS as usize {
        unsafe { Ok(out_0.assume_init() as CUgreenCtx) }
    } else {
        Err(unsafe { std::mem::transmute(status) })
    }
}
#[doc = "Destroys a green context\nDestroys the green context, releasing the primary context of the device that this green context was created for.\nAny resources provisioned for this green context (that were initially available via the resource descriptor)\nare released as well.\nThe API does not destroy streams created via ::cuGreenCtxStreamCreate, ::cuStreamCreate, or ::cuStreamCreateWithPriority.\nUsers are expected to destroy these streams explicitly using ::cuStreamDestroy to avoid resource leaks. Once the green context is destroyed,\nany subsequent API calls involving these streams will return ::CUDA_ERROR_STREAM_DETACHED with the exception of the following APIs:\n- ::cuStreamDestroy.\nAdditionally, the API will invalidate all active captures on these streams.\n\n# Arguments\n\n* `hCtx` - - Green context to be destroyed\n\n# Returns\n\n::CUDA_SUCCESS,\n::CUDA_ERROR_DEINITIALIZED,\n::CUDA_ERROR_NOT_INITIALIZED,\n::CUDA_ERROR_INVALID_CONTEXT,\n::CUDA_ERROR_CONTEXT_IS_DESTROYED\n\n# See also\n\n> [`::cuGreenCtxCreate,`]\n::cuCtxDestroy"]
pub unsafe fn cuGreenCtxDestroy(hCtx: CUgreenCtx) -> Result<(), crate::sys::CUresult> {
    let status = unsafe { crate::sys::cuGreenCtxDestroy(hCtx) };
    if status == crate::sys::CUresult::CUDA_SUCCESS { Ok(()) } else { Err(status) }
}
#[doc = "Converts a green context into the primary context\nThe API converts a green context into the primary context returned in `pContext.` It is important\nto note that the converted context `pContext` is a normal primary context but with\nthe resources of the specified green context `hCtx.` Once converted, it can then\nbe used to set the context current with ::cuCtxSetCurrent or with any of the CUDA APIs\nthat accept a CUcontext parameter.\nUsers are expected to call this API before calling any CUDA APIs that accept a\nCUcontext. Failing to do so will result in the APIs returning ::CUDA_ERROR_INVALID_CONTEXT.\n\n# Arguments\n\n* `pContext` - Returned primary context with green context resources\n* `hCtx` - Green context to convert\n\n# Returns\n\n::CUDA_SUCCESS,\n::CUDA_ERROR_DEINITIALIZED,\n::CUDA_ERROR_NOT_INITIALIZED,\n::CUDA_ERROR_INVALID_CONTEXT,\n::CUDA_ERROR_INVALID_VALUE\n\n# See also\n\n> [`::cuGreenCtxCreate`]"]
pub unsafe fn cuCtxFromGreenCtx(pContext: *mut CUcontext, hCtx: CUgreenCtx) -> Result<(), crate::sys::CUresult> {
    let status = unsafe { crate::sys::cuCtxFromGreenCtx(pContext, hCtx) };
    if status == crate::sys::CUresult::CUDA_SUCCESS { Ok(()) } else { Err(status) }
}
#[doc = "Get device resources\nGet the `type` resources available to the `device.`\nThis may often be the starting point for further partitioning or configuring of resources.\nNote: The API is not supported on 32-bit platforms.\n\n# Arguments\n\n* `device` - - Device to get resource for\n* `resource` - - Output pointer to a CUdevResource structure\n* `type` - - Type of resource to retrieve\n\n# Returns\n\n::CUDA_SUCCESS,\n::CUDA_ERROR_DEINITIALIZED,\n::CUDA_ERROR_NOT_INITIALIZED,\n::CUDA_ERROR_INVALID_RESOURCE_TYPE,\n::CUDA_ERROR_INVALID_VALUE,\n::CUDA_ERROR_INVALID_DEVICE\n\n# See also\n\n> [`::cuDevResourceGenerateDesc`]"]
pub unsafe fn cuDeviceGetDevResource(device: CUdevice, type_: CUdevResourceType) -> Result<CUdevResource, crate::sys::CUresult> {
    let mut out_1: std::mem::MaybeUninit<CUdevResource> = std::mem::MaybeUninit::zeroed();
    let status = unsafe { crate::sys::cuDeviceGetDevResource(device, out_1.as_mut_ptr() as *mut _, type_) };
    if status as usize == crate::sys::CUresult::CUDA_SUCCESS as usize {
        unsafe { Ok(out_1.assume_init() as CUdevResource) }
    } else {
        Err(unsafe { std::mem::transmute(status) })
    }
}
